    // 初始化温度场热力图
    initTempfieldChart() {
        const chartDom = document.getElementById('tempfield-chart');
        const chart = echarts.init(chartDom);
        
        // 生成模拟数据，与图片样式一致
        // 生成时间轴数据
        const timeValues = [];
        for (let i = 0; i < 7; i++) {
            const date = new Date('2026-01-14');
            date.setDate(date.getDate() + i);
            timeValues.push(date.toISOString().slice(0, 10));
        }
        
        // 生成深度轴数据
        const depthValues = [];
        for (let i = 0; i <= 127; i++) {
            depthValues.push(-i);
        }
        
        // 生成温度场数据（热力图数据）
        const temperatureData = [];
        for (let i = 0; i < depthValues.length; i++) {
            const row = [];
            for (let j = 0; j < timeValues.length; j++) {
                // 模拟温度数据，根据深度生成不同范围的温度
                let baseTemp = 20;
                if (depthValues[i] >= -50 && depthValues[i] <= -45) {
                    baseTemp = 35; // 中间绿色区域温度较高
                } else if (depthValues[i] >= -10 && depthValues[i] <= -1) {
                    baseTemp = 25; // 顶部区域温度较高
                } else if (depthValues[i] >= -120 && depthValues[i] <= -80) {
                    baseTemp = 15; // 底部区域温度较低
                }
                // 添加随机波动
                const temp = baseTemp + (Math.random() - 0.5) * 5;
                row.push(temp.toFixed(2));
            }
            temperatureData.push(row);
        }
        
        // 生成右侧高程数据
        const elevationData = [];
        for (let i = 0; i < depthValues.length; i++) {
            // 模拟高程数据，随深度变化
            const elevation = 1024.94 - Math.abs(depthValues[i]) * 0.5;
            elevationData.push(elevation.toFixed(2));
        }
        
        const option = {
            title: {
                show: false
            },
            tooltip: {
                trigger: 'axis',
                axisPointer: {
                    type: 'cross'
                },
                formatter: function(params) {
                    return '深度: ' + params[0].value[0] + ' m<br/>温度: ' + params[0].value[2] + ' ℃<br/>高程: ' + elevationData[-params[0].value[0]] + ' m';
                }
            },
            grid: {
                left: '8%',
                right: '15%',
                bottom: '15%',
                top: '10%',
                containLabel: true
            },
            xAxis: {
                type: 'category',
                data: timeValues,
                axisLabel: {
                    fontSize: 10,
                    rotate: 45
                },
                axisLine: {
                    lineStyle: {
                        color: '#666'
                    }
                },
                axisTick: {
                    alignWithLabel: true
                }
            },
            yAxis: [
                {
                    type: 'category',
                    data: depthValues,
                    axisLabel: {
                        fontSize: 10,
                        formatter: '{value} m'
                    },
                    axisLine: {
                        lineStyle: {
                            color: '#666'
                        }
                    },
                    splitLine: {
                        show: true,
                        lineStyle: {
                            color: '#f0f0f0'
                        }
                    }
                },
                {
                    type: 'category',
                    data: elevationData,
                    axisLabel: {
                        fontSize: 10,
                        formatter: '{value} m'
                    },
                    axisLine: {
                        show: true,
                        lineStyle: {
                            color: '#666'
                        }
                    },
                    axisTick: {
                        show: false
                    },
                    position: 'right'
                }
            ],
            visualMap: {
                type: 'continuous',
                min: 0,
                max: 40,
                orient: 'vertical',
                right: '5%',
                top: 'center',
                text: ['40℃', '0℃'],
                textStyle: {
                    fontSize: 10
                },
                inRange: {
                    color: ['#0000ff', '#00ffff', '#00ff00', '#ffff00', '#ff0000']
                },
                calculable: true
            },
            series: [{
                name: '温度场',
                type: 'heatmap',
                data: function() {
                    const data = [];
                    for (let i = 0; i < depthValues.length; i++) {
                        for (let j = 0; j < timeValues.length; j++) {
                            data.push([j, i, parseFloat(temperatureData[i][j])]);
                        }
                    }
                    return data;
                }(),
                label: {
                    show: false
                },
                emphasis: {
                    itemStyle: {
                        shadowBlur: 10,
                        shadowColor: 'rgba(0, 0, 0, 0.5)'
                    }
                }
            }]
        };
        
        chart.setOption(option);
    },
    
