            let rowData = [cells[0].innerText, cells[1].innerText, cells[2].innerText, cells[3].innerText];
            selectedCols.forEach(col => {
                const idx = allTableCols.indexOf(col);
                if (idx !== -1) rowData.push(cells[idx].innerText.replace(/,/g, ""));
            });
